Javascript.initialise:
var erDate = null;
var dsd = WPU._getDsDOM();
var erdateNode = dsd.selectSingleNode("params/param/ds/ManageCase/DetailsOfClaim/DateRequestReceived");
erDate = XML.getNodeTextContent(erdateNode);
Services.setValue(DateOfPetition.dataBinding, erDate);

Javascript.validation:
			//Date picker: error message “The value does not conform to a valid date format of DD-MMM-YYYY”.
			//Validation: Date cannot be in the future
             return isInPast(Services.getValue(DateOfPetition.dataBinding),"false");

Javascript.validate:

			var err = null;
			var isFuture = isFutureDate(Services.getValue(DateOfPetition.dataBinding));
			if( null != isFuture && isFuture )
			{ err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
			}
			return err;
